final class PaymentManager: NSObject, ObservableObject {
    private var paymentSheet: PaymentSheet?

    func prepareDemoPayment() {
        let paymentIntentClientSecret = "pi_demo_client_secret_12345"
        var configuration = PaymentSheet.Configuration()
        configuration.merchantDisplayName = "Investor Demo"
        configuration.applePay = .init(
            merchantId: "merchant.com.investor.demo",
            merchantCountryCode: "US"
        )
        paymentSheet = PaymentSheet(paymentIntentClientSecret: paymentIntentClientSecret, configuration: configuration)
    }

    func presentPaymentSheet(completion: @escaping (Result<Void, Error>) -> Void) {
        guard let paymentSheet else {
            completion(.failure(NSError(domain: "PaymentSheet", code: -1, userInfo: [NSLocalizedDescriptionKey: "Payment sheet not ready."])))
            return
        }

        guard let rootVC = UIApplication.shared.connectedScenes
            .compactMap({ $0 as? UIWindowScene })
            .flatMap({ $0.windows })
            .first(where: { $0.isKeyWindow })?
            .rootViewController else {
            completion(.failure(NSError(domain: "PaymentSheet", code: -2, userInfo: [NSLocalizedDescriptionKey: "Unable to find root view controller."])))
            return
        }

        paymentSheet.present(from: rootVC) { paymentResult in
            switch paymentResult {
            case .completed:
                completion(.success(()))
            case .canceled:
                completion(.failure(NSError(domain: "PaymentSheet", code: -3, userInfo: [NSLocalizedDescriptionKey: "Payment canceled."])))
            case .failed(let error):
                completion(.failure(error))
            }
        }
    }
}